package grpc

import (
	"fmt"
	"net"

	"google.golang.org/grpc"
)

type Server struct {
	grpcServer *grpc.Server
	listener   net.Listener
	port       int
}

func NewServer(port int, opts ...grpc.ServerOption) (*Server, error) {
	lis, err := net.Listen("tcp", fmt.Sprintf(":%d", port))
	if err != nil {
		return nil, fmt.Errorf("listen: %w", err)
	}
	s := grpc.NewServer(opts...)
	return &Server{grpcServer: s, listener: lis, port: port}, nil
}

func (s *Server) Start() error {
	return s.grpcServer.Serve(s.listener)
}

func (s *Server) Stop() {
	s.grpcServer.GracefulStop()
}

package main

import (
	"log/slog"
	"os"

	"github.com/Bearil/vector-srv/pkg/config"
	"github.com/Bearil/vector-srv/internal/delivery/grpc"
)

func main() {
	cfg, err := config.Load("config.yaml")
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}
	server, err := grpc.NewServer(cfg.Port)
	if err != nil {
		slog.Error("server error", "error", err)
		os.Exit(1)
	}
	server.Start()
}

package config

import (
	"fmt"
	"os"

	"gopkg.in/yaml.v3"
)

type Config struct {
	Port     int    `yaml:"port"`
	LogLevel string `yaml:"log_level"`
	Model    string `yaml:"model"`
}

func Load(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("read config: %w", err)
	}
	var cfg Config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parse config: %w", err)
	}
	return &cfg, nil
}

package grpc

import (
	"context"
	"log/slog"

	pb "github.com/Bearil/vector-srv/api/proto"
	"github.com/Bearil/vector-srv/internal/usecase/answer_question"
)

type FlowHandler struct {
	pb.UnimplementedFlowServiceServer
	usecase *answer_question.Usecase
}

func NewFlowHandler(uc *answer_question.Usecase) *FlowHandler {
	return &FlowHandler{usecase: uc}
}

func (h *FlowHandler) Stream(req *pb.StreamRequest, stream pb.FlowService_StreamServer) error {
	ctx := stream.Context()
	slog.InfoContext(ctx, "stream started", "session_id", req.GetSessionId())
	return nil
}
